// server.js - Hostinger Optimized Version
const express = require("express");
const axios = require("axios");
const https = require("https");
const fs = require("fs").promises;
const path = require("path");
const compression = require("compression");
const crypto = require("crypto");

const app = express();

// ================= HOSTINGER-SPECIFIC CONFIG =================
const PORT = process.env.PORT || 3000; // Hostinger uses 3000-3009
const STORAGE_FILE = path.join(__dirname, "storage.json");

// Hostinger doesn't support .env files - use their dashboard environment variables
const API_KEY = process.env.DEEPSEEK_API_KEY;
if (!API_KEY) {
    console.error("❌ DEEPSEEK_API_KEY environment variable not set!");
    console.error("💡 Set it in Hostinger Control Panel → Node.js → Environment Variables");
    process.exit(1);
}

const DEEPSEEK_URL = "https://api.deepseek.com/chat/completions";

// ================= HOSTINGER FILE SYSTEM SETUP =================
async function ensureStorage() {
    try {
        await fs.access(STORAGE_FILE);
    } catch {
        // Create initial storage with proper permissions
        const initial = { 
            projects: [], 
            version: "1.0.0",
            createdAt: new Date().toISOString()
        };
        await fs.writeFile(STORAGE_FILE, JSON.stringify(initial, null, 2));
        console.log("📁 Storage file created");
    }
}

// ================= OPTIMIZED FOR HOSTINGER =================
const axiosInstance = axios.create({
    httpsAgent: new https.Agent({ 
        keepAlive: true,
        maxSockets: 10, // Reduced for Hostinger memory limits
        timeout: 30000
    }),
    timeout: 45000 // Hostinger has 60s execution limit
});

app.use(compression({ level: 3 })); // Lower compression for CPU savings
app.use(express.json({ limit: "5mb" })); // Reduced limit

// ================= SIMPLE RATE LIMITING =================
const requestCounts = new Map();
const MAX_REQUESTS_PER_MINUTE = 30;

app.use((req, res, next) => {
    const ip = req.ip || req.connection.remoteAddress;
    const now = Date.now();
    const minuteAgo = now - 60000;

    if (!requestCounts.has(ip)) {
        requestCounts.set(ip, []);
    }

    const requests = requestCounts.get(ip).filter(time => time > minuteAgo);
    requestCounts.set(ip, requests);

    if (requests.length >= MAX_REQUESTS_PER_MINUTE) {
        return res.status(429).json({ 
            error: "Rate limit exceeded. Please try again in a minute." 
        });
    }

    requests.push(now);
    next();
});

// Cleanup old requests every 5 minutes
setInterval(() => {
    const now = Date.now();
    for (const [ip, times] of requestCounts.entries()) {
        const recent = times.filter(time => now - time < 300000); // 5 minutes
        if (recent.length === 0) {
            requestCounts.delete(ip);
        } else {
            requestCounts.set(ip, recent);
        }
    }
}, 300000);

// ================= DATABASE WITH FILE LOCKING =================
let fileLock = false;
const LOCK_TIMEOUT = 5000;

async function withFileLock(operation) {
    const startTime = Date.now();

    while (fileLock && Date.now() - startTime < LOCK_TIMEOUT) {
        await new Promise(resolve => setTimeout(resolve, 100));
    }

    if (fileLock) {
        throw new Error("Database lock timeout");
    }

    fileLock = true;
    try {
        return await operation();
    } finally {
        fileLock = false;
    }
}

async function loadDB() {
    return withFileLock(async () => {
        try {
            const data = await fs.readFile(STORAGE_FILE, "utf8");
            return JSON.parse(data);
        } catch (error) {
            console.error("Error loading DB:", error);
            return { projects: [], version: "1.0.0" };
        }
    });
}

async function saveDB(data) {
    return withFileLock(async () => {
        const tempFile = STORAGE_FILE + ".tmp";
        try {
            await fs.writeFile(tempFile, JSON.stringify(data, null, 2));
            await fs.rename(tempFile, STORAGE_FILE);
        } catch (error) {
            console.error("Error saving DB:", error);
            throw error;
        }
    });
}

