});

// ================= STREAMING CHAT (HOSTINGER OPTIMIZED) =================
app.post("/chat/stream", async (req, res) => {
    const { message, projectId } = req.body;

    if (!message || !projectId) {
        return res.status(400).json({ error: "Missing parameters" });
    }

    if (message.length > 2000) {
        return res.status(400).json({ error: "Message too long" });
    }

    res.writeHead(200, {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive"
    });

    try {
        const messages = [
            { 
                role: "system", 
                content: "You are a Senior Engineer. Provide technical code in markdown blocks. No fluff." 
            },
            { role: "user", content: message }
        ];

        const response = await axiosInstance.post(
            DEEPSEEK_URL,
            {
                model: "deepseek-chat",
                messages: messages,
                stream: true,
                max_tokens: 2000,
                temperature: 0.7
            },
            {
                headers: { 
                    Authorization: `Bearer ${API_KEY}`,
                    "Content-Type": "application/json"
                },
                responseType: "stream",
                timeout: 40000
            }
        );

        let fullResponse = "";

        response.data.on("data", (chunk) => {
            const lines = chunk.toString().split('\n');
            for (const line of lines) {
                if (line.startsWith('data: ') && line !== 'data: [DONE]') {
                    try {
                        const data = JSON.parse(line.slice(6));
                        const content = data.choices?.[0]?.delta?.content || "";
                        if (content) {
                            fullResponse += content;
                            res.write(`data: ${JSON.stringify({ content })}\n\n`);
                        }
                    } catch (e) {
                        // Ignore parse errors
                    }
                }
            }
        });

        response.data.on("end", () => {
            // Save to database asynchronously (don't wait)
            saveToDatabase(projectId, message, fullResponse).catch(console.error);
            res.write("event: complete\ndata: {}\n\n");
            res.end();
        });

        response.data.on("error", (error) => {
            console.error("Stream error:", error);
            res.write(`event: error\ndata: ${JSON.stringify({ error: "Stream failed" })}\n\n`);
            res.end();
        });

        req.on("close", () => {
            response.data.destroy();
        });

    } catch (error) {
        console.error("Chat error:", error.message);
        res.write(`event: error\ndata: ${JSON.stringify({ error: "Service unavailable" })}\n\n`);
        res.end();
    }
});

async function saveToDatabase(projectId, userMessage, aiResponse) {
    try {
        const db = await loadDB();
        const project = db.projects.find(p => p.id === projectId);

        if (project) {
            project.history = project.history || [];
            project.history.push(
                { role: "user", content: userMessage },
                { role: "assistant", content: aiResponse }
            );

            // Keep only last 20 messages to prevent file bloat
            if (project.history.length > 40) {
                project.history = project.history.slice(-40);
            }

            await saveDB(db);
        }
    } catch (error) {
        console.error("Failed to save chat:", error);
    }
}

